const body = $input.first().json.body || $input.first().json;
const { action, username, password, filename, content, manifest } = body;
const server = (body.server || 'nuage03.apps.education.fr').replace(/^https?:\/\//, '').replace(/\/$/, '');

if (!username || !password) {
  return [{ json: { success: false, error: 'Identifiants manquants' } }];
}

const baseUrl = `https://${server}/remote.php/dav/files/${encodeURIComponent(username)}/experia/`;
const manifestUrl = baseUrl + 'manifest.json';
const auth = 'Basic ' + Buffer.from(`${username}:${password}`).toString('base64');

const doGet = async (url) => {
  return await this.helpers.httpRequest({
    method: 'GET', url,
    headers: { 'Authorization': auth },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
};

const doPut = async (url, data) => {
  return await this.helpers.httpRequest({
    method: 'PUT', url,
    headers: { 'Authorization': auth, 'Content-Type': 'application/octet-stream' },
    body: data,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
};

const doMkcol = async (url) => {
  return await this.helpers.httpRequest({
    method: 'MKCOL', url,
    headers: { 'Authorization': auth },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
};

const doDelete = async (url) => {
  return await this.helpers.httpRequest({
    method: 'DELETE', url,
    headers: { 'Authorization': auth },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
};

const readManifest = async () => {
  const r = await doGet(manifestUrl);
  if (r.statusCode !== 200) return [];
  try {
    const p = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
    return Array.isArray(p) ? p : [];
  } catch { return []; }
};

const writeManifest = async (mf) => {
  await doPut(manifestUrl, JSON.stringify(mf));
};

try {

  // ── TEST connexion ──────────────────────────────────────────────────────────
  if (action === 'test') {
    const ocsUrl = `https://${server}/ocs/v1.php/cloud/user?format=json`;
    const r = await this.helpers.httpRequest({
      method: 'GET', url: ocsUrl,
      headers: { 'Authorization': auth, 'OCS-APIREQUEST': 'true' },
      returnFullResponse: true, ignoreHttpStatusErrors: true
    });
    if (r.statusCode === 401 || r.statusCode === 403)
      return [{ json: { success: false, error: "Identifiants invalides — vérifiez votre mot de passe d'application." } }];
    if (r.statusCode !== 200)
      return [{ json: { success: false, error: 'Erreur OCS: ' + r.statusCode + ' — vérifiez votre serveur Nuage.' } }];
    // Créer le dossier experia/ si nécessaire
    await doMkcol(baseUrl);
    return [{ json: { success: true, action: 'test', server, username } }];
  }

  // ── LIST fichiers ───────────────────────────────────────────────────────────
  if (action === 'list') {
    const mf = await readManifest();
    return [{ json: { success: true, files: mf.map(n => ({ name: n })) } }];
  }

  // ── READ fichier ────────────────────────────────────────────────────────────
  if (action === 'read') {
    if (!filename) return [{ json: { success: false, error: 'Nom de fichier manquant' } }];
    const r = await doGet(baseUrl + encodeURIComponent(filename));
    if (r.statusCode === 404) return [{ json: { success: false, error: 'Fichier introuvable' } }];
    if (r.statusCode === 401) return [{ json: { success: false, error: 'Session expirée' } }];
    if (r.statusCode >= 400) return [{ json: { success: false, error: 'Erreur lecture (code ' + r.statusCode + ')' } }];
    try {
      const parsed = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
      return [{ json: { success: true, content: parsed } }];
    } catch(e) {
      return [{ json: { success: false, error: 'Fichier corrompu : ' + e.message } }];
    }
  }

  // ── WRITE fichier ───────────────────────────────────────────────────────────
  if (action === 'write') {
    if (!filename) return [{ json: { success: false, error: 'Nom de fichier manquant' } }];
    const fileContent = typeof content === 'string' ? content : JSON.stringify(content, null, 2);
    const putUrl = baseUrl + encodeURIComponent(filename);

    // Premier essai
    let putRes = await doPut(putUrl, fileContent);

    // Si le dossier n'existe pas encore → MKCOL puis retry
    if ([404, 405, 409].includes(putRes.statusCode)) {
      await doMkcol(baseUrl);
      putRes = await doPut(putUrl, fileContent);
    }

    if (putRes.statusCode >= 400)
      return [{ json: { success: false, error: 'Erreur écriture (code ' + putRes.statusCode + ')' } }];

    // Mettre à jour manifest.json
    let mf = await readManifest();
    if (!mf.includes(filename)) mf.push(filename);
    await writeManifest(mf);

    return [{ json: { success: true, action: 'write' } }];
  }

  // ── DELETE fichier ──────────────────────────────────────────────────────────
  if (action === 'delete') {
    if (!filename) return [{ json: { success: false, error: 'Nom de fichier manquant' } }];
    await doDelete(baseUrl + encodeURIComponent(filename));
    let mf = await readManifest();
    await writeManifest(mf.filter(n => n !== filename));
    return [{ json: { success: true, action: 'delete' } }];
  }

  return [{ json: { success: false, error: 'Action inconnue : ' + action } }];

} catch(e) {
  return [{ json: { success: false, error: e.message } }];
}
